/**
 * @fileoverview Dialog component - modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js - CSS classes, z-index base, SVG icons, defaults
 *   helpers.js   - setContent (resolve string / template / element)
 *   state.js     - stack management, reactive locked/loading state
 *   view.js      - DOM construction, mount / unmount, tab-trap
 *   events.js    - global Escape handler, overlay-click binding
 *
 * @module module/Dialog
 */

import { default as razyui } from '../../index.js';
import { DialogDef as DEF } from '../Dialog.def.js';

import { DEFAULTS }                                        from './constants.js';
import { setContent }                                            from './helpers.js';
import { pushStack, popStack, getStack,
         createReactiveState, wireEffects }                      from './state.js';
import { buildDialogDOM, buildButtons, mountDialog,
         unmountDialog }                                        from './view.js';
import { bindEscapeHandler, bindOverlayClose, setupTabTrap }     from './events.js';

/**
 * Dialog - v2 modular rewrite
 *
 * Full-featured modal dialog system with overlay mask, stacking support,
 * promise-based API, reactive state, and configurable presets.
 *
 * Features:
 *   - Overlay mask with click-outside-to-close (configurable)
 *   - Presets: alert, confirm, prompt, window
 *   - Promise-based: Dialog.alert/confirm/prompt return Promises
 *   - Stacking popups - z-index management, Escape closes innermost
 *   - Template / HTML content - string, element, or <template> selector
 *   - Header with title + close button
 *   - Footer with configurable buttons (text, color, action)
 *   - Animate in/out with CSS transitions
 *   - Size presets: sm, md, lg, xl, full (or custom width/height)
 *   - Reactive state: locked (submit in progress), loading
 *   - getControl() API: close(), lock(), unlock(), setTitle(), setContent()
 *   - Keyboard: Escape to close, Tab-trap inside modal
 *   - Body scroll-lock while any popup is open
 *   - AjaxForm integration: form:true auto-wraps <form> in popup body
 *
 * Static API:
 *   Dialog.alert(title, message, config?)       -> Promise<void>
 *   Dialog.confirm(title, message, config?)     -> Promise<boolean>
 *   Dialog.prompt(title, message, config?)      -> Promise<string|null>
 *   Dialog.open(config)                         -> Dialog instance
 *   Dialog.closeAll()                           -> void
 *
 * Config:
 *   title        - header title (string or HTML)
 *   content      - body content (string HTML, Element, or template selector)
 *   size         - 'sm' | 'md' | 'lg' | 'xl' | 'full' (default 'md')
 *   width        - custom CSS width (overrides size)
 *   height       - custom CSS height
 *   closable     - allow close via x / Escape / overlay click (default true)
 *   overlayClose - close on overlay click (default true)
 *   buttons      - array of { id?, text, color?, action?, close? } for footer (right)
 *   leftButtons  - array of { id?, text, color?, action?, close? } for footer (left)
 *
 * Callbacks:
 *   onOpen(ctrl)         - fires after popup is mounted
 *   onClose(ctrl)        - fires before popup is removed
 *   onConfirm(ctrl)      - fires on confirm button click (return false to prevent close)
 *   onCancel(ctrl)       - fires on cancel button click
 *
 * @class Dialog
 * @param {object} config - Configuration options for the Dialog.
 */

// ── Dialog class ───────────────────────────────

/** Registry of currently-open dialog IDs → Dialog instances (dedup guard). */
const _openIds = new Map();

const Dialog = class {
    #overlay = null;
    #destroyed = false;
    #dialog = null;
    #headerEl = null;
    #titleEl = null;
    #closeBtn = null;
    #bodyEl = null;
    #footerEl = null;
    #promptInput = null;

    #config = {};
    #stateRef = null;
    #setState = null;
    #resolve = null;     // Promise resolve for alert/confirm/prompt
    #reject = null;
    #closed = false;
    #formInstance = null; // AjaxForm instance if form integration is used

    get closable() {
        return this.#config.closable !== false;
    }

    constructor(config = {}) {
        this.#config = { ...DEFAULTS, ...config };

        // ── Duplicate-ID guard ──
        // If an `id` is provided and a dialog with the same id is already open,
        // bring the existing one to focus and skip creating a new instance.
        if (this.#config.id != null) {
            const existing = _openIds.get(this.#config.id);
            if (existing && !existing.#closed) {
                // Return the existing instance — caller can detect via Dialog.open()
                return existing;
            }
            _openIds.set(this.#config.id, this);
        }

        bindEscapeHandler();
        this.#buildDOM();
        this.#setupState();
        this.#mount();
    }

    // ────────────────────────────────────────────
    // DOM
    // ────────────────────────────────────────────

    #buildDOM() {
        const cfg = this.#config;

        const { overlay, dialog, header, title, closeBtn, body, footer, promptInput } =
            buildDialogDOM(razyui, cfg);

        // Close button click
        if (closeBtn) {
            razyui(closeBtn).on('click', () => this.close());
        }

        // Overlay click-to-close
        if (cfg.closable && cfg.overlayClose !== false) {
            bindOverlayClose(overlay, () => this.close());
        }

        // Prompt - Enter to confirm
        if (promptInput) {
            razyui(promptInput).on('keydown', (e) => {
                if (e.key === 'Enter') {
                    e.preventDefault();
                    this.#handleConfirm();
                }
            });
        }

        this.#overlay = overlay;
        this.#dialog = dialog;
        this.#headerEl = header;
        this.#titleEl = title;
        this.#closeBtn = closeBtn;
        this.#bodyEl = body;
        this.#footerEl = footer;
        this.#promptInput = promptInput;

        this.#renderFooterButtons();
    }

    #normalizeButtons(buttons) {
        if (!Array.isArray(buttons)) return [];
        return buttons.map(btn => (razyui.isPO(btn) ? { ...btn } : btn));
    }

    #removeButtonById(buttons, id) {
        if (!Array.isArray(buttons) || id == null) return false;
        const idx = buttons.findIndex(btn => razyui.isPO(btn) && btn.id === id);
        if (idx === -1) return false;
        buttons.splice(idx, 1);
        return true;
    }

    #wireFooterButton(el, btn) {
        razyui(el).on('click', async () => {
            if (this.#stateRef?.locked) return;

            if (btn.role === 'confirm') {
                this.#handleConfirm();
                return;
            }

            if (btn.role === 'cancel') {
                this.#handleCancel();
                return;
            }

            if (typeof btn.action === 'function') {
                this.#setState({ locked: true });
                try {
                    const result = await btn.action(this.getControl());
                    if (result !== false && btn.close !== false) {
                        this.close();
                    }
                } catch (err) {
                    // stay open on error
                } finally {
                    this.#setState({ locked: false });
                }
            } else if (btn.close !== false) {
                this.close();
            }
        });
    }

    #renderFooterButtons() {
        const cfg = this.#config;
        const footer = this.#footerEl;
        if (!footer) return;

        razyui(footer).html('');

        if (Array.isArray(cfg.leftButtons) && cfg.leftButtons.length > 0) {
            const leftBtnEls = buildButtons(footer, cfg.leftButtons, true);
            leftBtnEls.forEach(({ el, btn }) => this.#wireFooterButton(el, btn));
        }

        if (Array.isArray(cfg.buttons) && cfg.buttons.length > 0) {
            const rightBtnEls = buildButtons(footer, cfg.buttons);
            rightBtnEls.forEach(({ el, btn }) => this.#wireFooterButton(el, btn));
        }

        if (this.#stateRef?.locked) {
            footer.querySelectorAll('.dialog-btn').forEach(btn => {
                btn.disabled = true;
            });
        }
    }

    // ────────────────────────────────────────────
    // State
    // ────────────────────────────────────────────

    #setupState() {
        const stateSet = createReactiveState(razyui);
        const [stateRef, setState] = stateSet;
        this.#stateRef = stateRef;
        this.#setState = setState;

        wireEffects(stateSet, this.#footerEl, this.#dialog);
    }

    // ────────────────────────────────────────────
    // Mount / unmount
    // ────────────────────────────────────────────

    #mount() {
        pushStack(this);
        mountDialog(this.#overlay, this.#dialog, this.#promptInput);
        setupTabTrap(this.#overlay, this.#dialog);

        // Auto-wrap form inside popup body (AjaxForm integration)
        if (this.#config.form) {
            this.#initForm();
        }

        // onOpen callback
        if (typeof this.#config.onOpen === 'function') {
            this.#config.onOpen(this.getControl());
        }
    }

    async #initForm() {
        const cfg = this.#config;
        const formEl = this.#bodyEl.querySelector('form');
        if (!formEl) return;

        // Lazy-load AjaxForm module via razyui.load (handles JS + CSS)
        const AjaxForm = await razyui.load('AjaxForm');

        const formConfig = typeof cfg.form === 'object' ? { ...cfg.form } : {};

        // Wire up success/error with popup
        const origSuccess = formConfig.onSuccess;
        const origError = formConfig.onError;
        const self = this;

        formConfig.onSuccess = function (data, response) {
            if (razyui.isFn(origSuccess)) {
                origSuccess.call(this, data, response);
            }
            if (cfg.closeOnSuccess !== false) {
                if (self.#resolve) {
                    self.#resolve(data);
                    self.#resolve = null;
                }
                self.close();
            }
        };

        formConfig.onError = function (errors, response) {
            if (razyui.isFn(origError)) {
                origError.call(this, errors, response);
            }
        };

        // Lock popup while submitting
        const origComplete = formConfig.onComplete;
        formConfig.onComplete = (ctrl) => {
            this.#setState({ locked: false });
            if (razyui.isFn(origComplete)) {
                origComplete(ctrl);
            }
        };

        const origValidation = formConfig.onValidation;
        formConfig.onValidation = async (data, ctrl) => {
            if (razyui.isFn(origValidation)) {
                const result = await origValidation(data, ctrl);
                if (result === false) {
                    this.#setState({ locked: false });
                    return false;
                }
            }
        };

        this.#formInstance = new AjaxForm(formEl, formConfig);
    }

    // ────────────────────────────────────────────
    // Confirm / Cancel handlers
    // ────────────────────────────────────────────

    async #handleConfirm() {
        const cfg = this.#config;

        if (this.#stateRef.locked) return;

        // If form integration is active, submit the form instead
        if (this.#formInstance) {
            this.#setState({ locked: true });
            this.#formInstance.getControl().submit();
            return;
        }

        this.#setState({ locked: true });

        try {
            if (typeof cfg.onConfirm === 'function') {
                const result = await cfg.onConfirm(this.getControl());
                if (result === false) {
                    this.#setState({ locked: false });
                    return;
                }
            }

            // Resolve promise
            if (this.#resolve) {
                if (cfg._mode === 'prompt') {
                    this.#resolve(this.#promptInput ? this.#promptInput.value : '');
                } else if (cfg._mode === 'confirm') {
                    this.#resolve(true);
                } else {
                    this.#resolve();
                }
                this.#resolve = null;
            }

            this.close();
        } catch {
            // stay open on error
        } finally {
            if (!this.#closed) {
                this.#setState({ locked: false });
            }
        }
    }

    #handleCancel() {
        const cfg = this.#config;

        if (typeof cfg.onCancel === 'function') {
            cfg.onCancel(this.getControl());
        }

        // Resolve promise with cancel value
        if (this.#resolve) {
            if (cfg._mode === 'confirm') {
                this.#resolve(false);
            } else if (cfg._mode === 'prompt') {
                this.#resolve(null);
            } else {
                this.#resolve();
            }
            this.#resolve = null;
        }

        this.close();
    }

    // ────────────────────────────────────────────
    // Public API
    // ────────────────────────────────────────────

    close() {
        if (this.#closed) return;
        this.#closed = true;

        // Remove from ID registry
        if (this.#config.id != null) {
            _openIds.delete(this.#config.id);
        }

        if (typeof this.#config.onClose === 'function') {
            this.#config.onClose(this.getControl());
        }

        // Reject any unresolved promise (defensive)
        if (this.#resolve) {
            if (this.#config._mode === 'confirm') {
                this.#resolve(false);
            } else if (this.#config._mode === 'prompt') {
                this.#resolve(null);
            } else {
                this.#resolve();
            }
            this.#resolve = null;
        }

        unmountDialog(this.#overlay, this.#dialog, () => popStack(this));
    }

    getControl() {
        const self = this;
        return {
            close: () => self.close(),
            get locked() { return self.#stateRef.locked; },
            lock:   () => self.#setState({ locked: true }),
            unlock: () => self.#setState({ locked: false }),
            setTitle: (title) => {
                razyui(self.#titleEl).html('');
                setContent(self.#titleEl, title);
            },
            setContent: (content) => {
                razyui(self.#bodyEl).html('');
                setContent(self.#bodyEl, content);
            },
            setLeftButtons: (buttons = []) => {
                self.#config.leftButtons = self.#normalizeButtons(buttons);
                self.#renderFooterButtons();
            },
            addLeftButton: (button = {}) => {
                if (!Array.isArray(self.#config.leftButtons)) self.#config.leftButtons = [];
                self.#config.leftButtons.push(razyui.isPO(button) ? { ...button } : button);
                self.#renderFooterButtons();
            },
            setButtons: (buttons = []) => {
                self.#config.buttons = self.#normalizeButtons(buttons);
                self.#renderFooterButtons();
            },
            addButton: (button = {}) => {
                if (!Array.isArray(self.#config.buttons)) self.#config.buttons = [];
                self.#config.buttons.push(razyui.isPO(button) ? { ...button } : button);
                self.#renderFooterButtons();
            },
            setRightButtons: (buttons = []) => {
                self.#config.buttons = self.#normalizeButtons(buttons);
                self.#renderFooterButtons();
            },
            addRightButton: (button = {}) => {
                if (!Array.isArray(self.#config.buttons)) self.#config.buttons = [];
                self.#config.buttons.push(razyui.isPO(button) ? { ...button } : button);
                self.#renderFooterButtons();
            },
            updateLeftButton: (index, detail = {}) => {
                if (!Array.isArray(self.#config.leftButtons)) self.#config.leftButtons = [];
                const curr = self.#config.leftButtons[index];
                if (!curr) return;
                self.#config.leftButtons[index] = { ...curr, ...detail };
                self.#renderFooterButtons();
            },
            removeLeftButtonById: (id) => {
                if (!Array.isArray(self.#config.leftButtons)) return false;
                const removed = self.#removeButtonById(self.#config.leftButtons, id);
                if (removed) self.#renderFooterButtons();
                return removed;
            },
            updateButton: (index, detail = {}) => {
                if (!Array.isArray(self.#config.buttons)) self.#config.buttons = [];
                const curr = self.#config.buttons[index];
                if (!curr) return;
                self.#config.buttons[index] = { ...curr, ...detail };
                self.#renderFooterButtons();
            },
            removeButtonById: (id) => {
                if (!Array.isArray(self.#config.buttons)) return false;
                const removed = self.#removeButtonById(self.#config.buttons, id);
                if (removed) self.#renderFooterButtons();
                return removed;
            },
            updateRightButton: (index, detail = {}) => {
                if (!Array.isArray(self.#config.buttons)) self.#config.buttons = [];
                const curr = self.#config.buttons[index];
                if (!curr) return;
                self.#config.buttons[index] = { ...curr, ...detail };
                self.#renderFooterButtons();
            },
            removeRightButtonById: (id) => {
                if (!Array.isArray(self.#config.buttons)) return false;
                const removed = self.#removeButtonById(self.#config.buttons, id);
                if (removed) self.#renderFooterButtons();
                return removed;
            },
            get dialog() { return self.#dialog; },
            get body() { return self.#bodyEl; },
            get footer() { return self.#footerEl; },
            get leftButtons() { return self.#normalizeButtons(self.#config.leftButtons); },
            get buttons() { return self.#normalizeButtons(self.#config.buttons); },
            get promptValue() { return self.#promptInput ? self.#promptInput.value : null; },
            /** Submit the embedded form (if form integration is active) */
            submitForm: () => { if (self.#formInstance) self.#formInstance.getControl().submit(); },
            /** Get the AjaxForm control (if form integration is active) */
            get formControl() { return self.#formInstance ? self.#formInstance.getControl() : null; },
            destroy: () => self.destroy(),
            get element() { return self.#overlay; },
            get destroyed() { return self.#destroyed; },
        };
    }

    /** Attach a promise resolver (used by static helpers) */
    _bindPromise(resolve, reject) {
        this.#resolve = resolve;
        this.#reject = reject;
    }

    /** Fully tear down the dialog — close + null all refs for GC. */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.close();
        if (this.#formInstance) {
            if (typeof this.#formInstance.destroy === 'function') this.#formInstance.destroy();
            this.#formInstance = null;
        }
        this.#overlay = null;
        this.#dialog = null;
        this.#headerEl = null;
        this.#titleEl = null;
        this.#closeBtn = null;
        this.#bodyEl = null;
        this.#footerEl = null;
        this.#promptInput = null;
        this.#stateRef = null;
        this.#setState = null;
        this.#config = null;
    }
};

// ────────────────────────────────────────────
// Static helpers
// ────────────────────────────────────────────

/**
 * Alert - simple message with OK button.
 * @param {string} title
 * @param {string} message
 * @param {object} [config]
 * @returns {Promise<void>}
 */
Dialog.alert = function (title, message, config = {}) {
    return new Promise((resolve) => {
        const inst = new Dialog(Object.assign({
            title,
            content: typeof message === 'string' ? `<p>${message}</p>` : message,
            _mode: 'alert',
            size: config.size || 'sm',
            buttons: [
                { text: config.confirmText || 'OK', color: 'accent', role: 'confirm' },
            ],
        }, config));
        inst._bindPromise(resolve);
    });
};

/**
 * Confirm - yes/no dialog, returns true on confirm, false on cancel.
 * @param {string} title
 * @param {string} message
 * @param {object} [config]
 * @returns {Promise<boolean>}
 */
Dialog.confirm = function (title, message, config = {}) {
    return new Promise((resolve) => {
        const inst = new Dialog(Object.assign({
            title,
            content: typeof message === 'string' ? `<p>${message}</p>` : message,
            _mode: 'confirm',
            size: config.size || 'sm',
            buttons: [
                { text: config.cancelText || 'Cancel', color: 'muted', role: 'cancel' },
                { text: config.confirmText || 'Confirm', color: 'accent', role: 'confirm' },
            ],
        }, config));
        inst._bindPromise(resolve);
    });
};

/**
 * Prompt - input dialog, returns typed value on confirm, null on cancel.
 * @param {string} title
 * @param {string} message
 * @param {object} [config]
 * @returns {Promise<string|null>}
 */
Dialog.prompt = function (title, message, config = {}) {
    return new Promise((resolve) => {
        const inst = new Dialog(Object.assign({
            title,
            content: typeof message === 'string' ? `<p>${message}</p>` : message,
            _mode: 'prompt',
            size: config.size || 'sm',
            buttons: [
                { text: config.cancelText || 'Cancel', color: 'muted', role: 'cancel' },
                { text: config.confirmText || 'OK', color: 'accent', role: 'confirm' },
            ],
        }, config));
        inst._bindPromise(resolve);
    });
};

/**
 * Open a fully custom popup.
 * @param {object} config
 * @returns {Dialog}
 */
Dialog.open = function (config = {}) {
    return new Dialog(config);
};

/**
 * Close all open popups (top-down).
 */
Dialog.closeAll = function () {
    const s = getStack();
    while (s.length > 0) {
        const top = s[s.length - 1];
        top.close();
    }
};

/** Alias for close - provided for API consistency. */
Dialog.prototype.destroy = Dialog.prototype.close;

export default Dialog;
