/**
 * @fileoverview Dialog helpers - pure utility functions.
 * @module module/Dialog/helpers
 */

import razyui from '../../index.js';

/**
 * Resolve `content` into a DOM container.
 *
 * Supports:
 *   - String HTML (rendered via innerHTML)
 *   - Template selector string (`#id` or `.class`) - clones content
 *   - HTMLTemplateElement - clones content
 *   - HTMLElement - appends directly
 *
 * @param {HTMLElement} container  Target DOM element
 * @param {string|HTMLTemplateElement|HTMLElement} content
 */
export function setContent(container, content) {
    if (typeof content === 'string') {
        // Check if it's a template selector
        if (content.startsWith('#') || content.startsWith('.')) {
            const tpl = razyui(content)[0];
            if (tpl && tpl.tagName === 'TEMPLATE') {
                razyui(container).append(tpl.content.cloneNode(true));
                return;
            } else if (tpl) {
                razyui(container).append(tpl.cloneNode(true));
                return;
            }
        }
        razyui(container).html(content);
    } else if (content instanceof HTMLTemplateElement) {
        razyui(container).append(content.content.cloneNode(true));
    } else if (content instanceof HTMLElement) {
        razyui(container).append(content);
    }
}
