/**
 * @fileoverview Dialog component definition for JIT pipeline.
 *
 * Bundles design tokens, state machine config, template slot definitions,
 * and Custom Element metadata.
 *
 * @module module/Dialog.def
 */

import razyui from '../index.js';
import { PART } from './Dialog/constants.js';

/**
 * Definition object for the Dialog component.
 * Contains metadata, tokens, states, template slots, variants, and observed attributes.
 * @type {object}
 */
export const DialogDef = {
    name: 'Dialog',
    tag: 'rui-dialog',

    // ═══════════════════════════════════════
    //  Design Tokens
    // ═══════════════════════════════════════
    tokens: {
        prefix: 'dlg',
        tokens: {
            'radius':             { ref: 'radius.md',         description: 'Dialog border radius' },
            'font-size':          { ref: 'font.size-sm',      description: 'Base font size' },
            'header-padding-x':   { value: '1rem',            description: 'Header horizontal padding' },
            'header-padding-y':   { value: '0.75rem',         description: 'Header vertical padding' },
            'header-gap':         { value: '0.5rem',          description: 'Header gap' },
            'title-font-size':    { value: '0.95rem',         description: 'Title font size' },
            'title-font-weight':  { value: '600',             description: 'Title font weight' },
            'title-line-height':  { value: '1.4',             description: 'Title line height' },
            'body-padding':       { ref: 'spacing.4',         description: 'Body content padding' },
            'body-line-height':   { value: '1.6',             description: 'Body line height' },
            'close-btn-size':     { value: '28px',            description: 'Close button size' },
            'close-btn-radius':   { ref: 'radius.sm',         description: 'Close button radius' },
            'sm-width':           { value: '360px',           description: 'Small dialog width' },
            'md-width':           { value: '480px',           description: 'Medium dialog width' },
            'lg-width':           { value: '640px',           description: 'Large dialog width' },
            'xl-width':           { value: '860px',           description: 'Extra-large dialog width' },
            'font-stack':         { ref: 'font.family',       description: 'Font family' },
            'bg':                 { ref: 'color.bg',          description: 'Dialog background' },
            'border':             { ref: 'color.border',      description: 'Border color' },
            'shadow':             { ref: 'shadow.lg',         description: 'Dialog shadow' },
            'text':               { ref: 'color.text',        description: 'Text color' },
            'text-muted':         { ref: 'color.text-muted',  description: 'Muted text' },
            'accent':             { ref: 'color.accent',      description: 'Accent color' },
        },
    },

    // ═══════════════════════════════════════
    //  State Machine (per-dialog lifecycle)
    // ═══════════════════════════════════════
    states: {
        initial: 'closed',
        states: {
            closed: {
                on: { OPEN: 'opening' },
            },
            opening: {
                on: { OPENED: 'open' },
            },
            open: {
                on: { CLOSE: 'closing', LOCK: 'locked' },
            },
            locked: {
                on: { UNLOCK: 'open', CLOSE: 'closing' },
            },
            closing: {
                on: { CLOSED: 'closed' },
            },
        },
        effects: {
            opening(ctx) {
                const { overlay, dialog } = ctx;
                razyui(overlay).addClass('is-active');
                razyui(dialog).addClass('is-active');
            },
            closing(ctx) {
                const { overlay, dialog } = ctx;
                razyui(overlay).removeClass('is-active');
                razyui(dialog).removeClass('is-active');
            },
            locked(ctx) {
                razyui(ctx.dialog).addClass('is-locked');
            },
            'locked:exit'(ctx) {
                razyui(ctx.dialog).removeClass('is-locked');
            },
        },
    },

    // ═══════════════════════════════════════
    //  Template Slots
    // ═══════════════════════════════════════
    template: {
        slots: {
            overlay: { element: 'div',    classes: ['dialog-overlay'] },
            box:     { element: 'div',    classes: ['dialog-box'],       role: 'dialog' },
            header:  { element: 'div',    classes: ['dialog-header'] },
            title:   { element: 'div',    classes: ['dialog-title'] },
            close:   { element: 'button', classes: ['dialog-close'] },
            body:    { element: 'div',    classes: ['dialog-body'] },
            footer:  { element: 'div',    classes: ['dialog-footer'] },
        },
    },

    // ═══════════════════════════════════════
    //  Variants (sizes)
    // ═══════════════════════════════════════
    variants: {
        sm:   { description: 'Small dialog (360px)' },
        md:   { description: 'Medium dialog (480px, default)' },
        lg:   { description: 'Large dialog (640px)' },
        xl:   { description: 'Extra-large dialog (860px)' },
        full: { description: 'Full-screen dialog' },
    },

    // ═══════════════════════════════════════
    //  JIT Parts
    // ═══════════════════════════════════════
    jitParts: {
        [PART.OVERLAY]: PART.OVERLAY,
        [PART.BOX]: PART.BOX,
        [PART.HEADER]: PART.HEADER,
        [PART.TITLE]: PART.TITLE,
        [PART.CLOSE]: PART.CLOSE,
        [PART.BODY]: PART.BODY,
        [PART.FOOTER]: PART.FOOTER,
        [PART.PROMPT]: PART.PROMPT,
        [PART.PROMPT_INPUT]: PART.PROMPT_INPUT,
        [PART.BTN_GROUP]: PART.BTN_GROUP,
        [PART.BTN_GROUP_LEFT]: PART.BTN_GROUP_LEFT,
        [PART.BTN]: PART.BTN,
    },

    styles: {},

    // ═══════════════════════════════════════
    //  Custom Element
    // ═══════════════════════════════════════
    observedAttrs: ['size', 'title', 'closable'],
    attrMap: {
        size: 'size',
        title: 'title',
        closable: 'closable',
    },
};

export default DialogDef;
