/**
 * @fileoverview Dialog view - DOM construction, mounting, tab-trap, teardown.
 * @module module/Dialog/view
 */

import razyui from '../../index.js';
import { zIndexRegistry } from '../shared/ZIndexRegistry.js';
import { BASE_Z, CLS, SVG, SPELL, TRANSITION_TIMEOUT, PART } from './constants.js';
import { setContent } from './helpers.js';
import { getStackSize } from './state.js';
import { querySlot } from '../shared/slots.js';

/**
 * Build the full dialog DOM tree via razyui.spell().
 *
 * Returns references to every significant element so the Dialog class
 * can wire events and state without querying the DOM later.
 *
 * @param {object} razyui  The razyui runtime
 * @param {object} cfg     Merged dialog configuration
 * @returns {{ overlay, dialog, header, title, closeBtn, body, footer, promptInput }}
 */
export function buildDialogDOM(razyui, cfg) {
    const size = getStackSize();

    // Core structure
    const dom = razyui.spell(SPELL.DIALOG, true);
    const overlay = dom[0];
    const dialog  = querySlot(overlay, 'box');
    const header  = querySlot(overlay, 'header');
    const title   = querySlot(overlay, 'title');
    const body    = querySlot(overlay, 'body');
    const footer  = querySlot(overlay, 'footer');

    // Add component root class so --dlg-* tokens cascade to all descendants
    razyui(overlay).addClass('dialog');

    // Overlay z-index
    zIndexRegistry.acquire(overlay);

    // Apply JIT part classes
    PART.OVERLAY.apply(overlay);
    PART.BOX.apply(dialog);
    PART.HEADER.apply(header);
    PART.TITLE.apply(title);
    PART.BODY.apply(body);
    PART.FOOTER.apply(footer);

    // Dialog
    const $dialog = razyui(dialog);
    const titleId = 'rui-dlg-title-' + Math.random().toString(36).slice(2, 8);
    title.id = titleId;
    $dialog.setAttr({ role: 'dialog', 'aria-modal': 'true', 'aria-labelledby': titleId });
    zIndexRegistry.acquire(dialog);

    // Size (resolve JIT tokens)
    if (cfg.width) {
        $dialog.css('width', razyui.JIT.TOKEN.resolveSize(cfg.width));
    } else if (cfg.size) {
        $dialog.addClass('dialog-' + cfg.size);
    }
    if (cfg.height) {
        $dialog.css('height', razyui.JIT.TOKEN.resolveSize(cfg.height));
    }

    // Title
    if (cfg.title) {
        if (typeof cfg.title === 'string') {
            razyui(title).html(cfg.title);
        } else {
            razyui(title).html('').append(cfg.title);
        }
    }

    // Close button
    let closeBtn = null;
    if (cfg.closable !== false) {
        closeBtn = razyui.spell(SPELL.CLOSE_BTN, true)[0];
        closeBtn.type = 'button';
        razyui(closeBtn).setAttr({ 'aria-label': 'Close' }).html(SVG.CLOSE);
        PART.CLOSE.apply(closeBtn);
        razyui(header).append(closeBtn);
    }

    // Body content
    if (cfg.content) {
        setContent(body, cfg.content);
    }

    // Prompt input
    let promptInput = null;
    if (cfg._mode === 'prompt') {
        const promptDom = razyui.spell(SPELL.PROMPT, true);
        const input = querySlot(promptDom[0], 'prompt-input') || promptDom.find('.' + CLS.PROMPT_INPUT)[0];
        input.type = 'text';
        if (cfg.placeholder) input.placeholder = cfg.placeholder;
        if (cfg.defaultValue != null) input.value = cfg.defaultValue;
        PART.PROMPT.apply(promptDom[0]);
        PART.PROMPT_INPUT.apply(input);
        razyui(body).append(promptDom[0]);
        promptInput = input;
    }

    return { overlay, dialog, header, title, closeBtn, body, footer, promptInput };
}

/**
 * Build footer buttons and append them to the footer element.
 *
 * @param {HTMLElement} footer   Footer container
 * @param {Array}       buttons  Button config array
 * @param {boolean}     [left=false]  If true, use left-aligned group
 * @returns {{ el: HTMLElement, btn: object }[]}  Element / config pairs for event wiring
 */
export function buildButtons(footer, buttons, left = false) {
    const group = razyui.el('div', { className: left ? CLS.BTN_GROUP_LEFT : CLS.BTN_GROUP });
    PART[left ? 'BTN_GROUP_LEFT' : 'BTN_GROUP'].apply(group[0]);

    const buttonEls = [];

    buttons.forEach(btn => {
        const el = razyui.el('button', { type: 'button', className: CLS.BTN });
        PART.BTN.apply(el[0]);
        if (btn.html) {
            el.html(btn.html);
        } else {
            el.text(btn.text || 'OK');
        }

        if (btn.color) el.addClass(CLS.BTN + '-' + btn.color);
        if (btn.className) el.addClass(...btn.className.split(' '));
        if (btn.id != null && btn.id !== '') el.setAttr({ 'data-btn-id': String(btn.id) });

        group.append(el);
        buttonEls.push({ el: el[0], btn });
    });

    razyui(footer).append(group[0]);
    return buttonEls;
}

/**
 * Mount the dialog overlay into the document, trigger enter animation,
 * and manage initial focus.
 *
 * @param {HTMLElement}      overlay      Overlay element
 * @param {HTMLElement}      dialog       Dialog box element
 * @param {HTMLElement|null} promptInput  Prompt input (if prompt mode)
 */
export function mountDialog(overlay, dialog, promptInput) {
    razyui(document.body).append(overlay);

    // Trigger enter animation
    requestAnimationFrame(() => {
        razyui(overlay).addClass(CLS.ACTIVE);
        razyui(dialog).addClass(CLS.ACTIVE);
    });

    // Focus management
    if (promptInput) {
        promptInput.focus();
        promptInput.select();
    } else {
        dialog.focus();
    }

    // Make dialog focusable for tab-trap
    razyui(dialog).setAttr({ tabindex: '-1' });
}

/**
 * Unmount a dialog with exit animation, then invoke a cleanup callback.
 *
 * @param {HTMLElement} overlay  Overlay element
 * @param {HTMLElement} dialog   Dialog box element
 * @param {Function}    onDone   Called after removal (e.g. popStack)
 */
export function unmountDialog(overlay, dialog, onDone) {
    // Exit animation
    razyui(overlay).removeClass(CLS.ACTIVE);
    razyui(dialog).removeClass(CLS.ACTIVE);

    const done = () => {
        if (overlay.parentNode) {
            zIndexRegistry.release(dialog);
            zIndexRegistry.release(overlay);
            overlay.remove();
        }
        onDone();
    };

    // Wait for CSS transition
    razyui(overlay).on('transitionend', done, { once: true });

    // Fallback if no transition fires
    setTimeout(done, TRANSITION_TIMEOUT);
}
